import{_ as r,o as a,c as t,ag as l}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"团队开发/编写规范.md","filePath":"团队开发/编写规范.md","lastUpdated":1775898880000}'),i={name:"团队开发/编写规范.md"};function o(n,e,s,d,c,h){return a(),t("div",null,[...e[0]||(e[0]=[l('<h3 id="写作准则" tabindex="-1">写作准则 <a class="header-anchor" href="#写作准则" aria-label="Permalink to &quot;写作准则&quot;">​</a></h3><p>编写高质量的技术文档应有一定写作准则，文档应该满足 <strong>3C 准则</strong>——清晰性（<code>clearly</code>）、简洁性（<code>concisely</code>）、一致性（<code>consistently</code>）。</p><ul><li><strong>清晰性</strong>：确保你的行文清晰而简单。</li><li><strong>简洁性</strong>：在撰写任何文档时，知道该说多少是很重要的，不能少说也不可多说。</li><li><strong>一致性</strong>：确保你在整个页面和多个页面中一致地使用相同的措辞。</li></ul><p>编写前要<strong>考虑文档的目标受众</strong>，根据受众的不同调整文档的编写策略。例如希望其他组队友读懂的文档就要比面向组内的文档更加详细描述一些专业名词。</p><p>编写文档时要有<strong>分类意识</strong>，尽可能将联系性强的内容集中在同一部分，防止出现同一知识碎片化分布在全篇的情况。</p><p>编写文档时要有<strong>聚类意识</strong>，不同文档之间之间内容不要太相似，如果内容相近可以考虑合并，避免出现同一内容多篇介绍但每一页内容过少的情况。</p><p>文档的开篇需要标注上文档最近修改日期以及参与者等信息（格式与本文相同），来保证内容的有效性。</p><h3 id="标题要求" tabindex="-1">标题要求 <a class="header-anchor" href="#标题要求" aria-label="Permalink to &quot;标题要求&quot;">​</a></h3><ul><li>文档使用的标题最多分四级。</li><li>下级标题不应该重复上一级标题的名字。</li><li>标题不能跨级，例如一级标题下不能直接出现三级标题。</li><li>尽量避免出现四级标题以防止章节过于复杂，第三级标题下并行的内容可以使用项目列表。</li><li>一级标题作为文章的标题只能有一个，二级标题是文章主要部分的大标题，三级标题是主要使用的末级标题。</li></ul><h3 id="文本要求" tabindex="-1">文本要求 <a class="header-anchor" href="#文本要求" aria-label="Permalink to &quot;文本要求&quot;">​</a></h3><ul><li>全角中文字符与半角英文字符之间，应有一个半角空格，全角中文字符与半角阿拉伯数字之间可以没有半角空格，但是上下文的格式应该统一。</li><li>要避免使用过长的句子，尽量使用简单句和并列句，能够肯定表达的意思就不要否定表达，避免使用双重否定句。</li><li>不要使用用非正式的语言，开玩笑或是玩梗用括号括起来，<s>要不然直接划掉</s>。</li><li>段落应该有清楚的主题，中心句放在段首对全段内容进行概述。一个段落的长度不应过长。</li><li>使用代词时（比如“其”、“该”、“此”、“这”等词）确保只有一个含义，并在上下文中指明不要出现歧义。</li></ul><h3 id="符号要求" tabindex="-1">符号要求 <a class="header-anchor" href="#符号要求" aria-label="Permalink to &quot;符号要求&quot;">​</a></h3><ul><li>如果整句为英文，则该句使用英文/半角标点。</li><li>中文语句中的标点符号，均应该采取全角符号，这样可以与全角文字保持视觉的一致。</li><li>点号（<strong>句号</strong>、逗号、顿号、分号、<strong>冒号</strong>）不得出现在标题的末尾。</li><li>句子末尾用括号加注时，句号应在括号之外。</li></ul><h3 id="参考与致谢" tabindex="-1">参考与致谢 <a class="header-anchor" href="#参考与致谢" aria-label="Permalink to &quot;参考与致谢&quot;">​</a></h3><p><a href="https://github.com/ruanyf/document-style-guide" target="_blank" rel="noreferrer">ruanyf/document-style-guide: 中文技术文档的写作规范</a></p><p><a href="https://developer.mozilla.org/zh-CN/docs/MDN/Writing_guidelines/Writing_style_guide" target="_blank" rel="noreferrer">文档写作规范 - MDN Web 文档项目 | MDN</a></p><p><a href="https://wiki-power.com/%E4%B8%AA%E4%BA%BA%E6%96%87%E6%A1%88%E6%8E%92%E7%89%88%E8%A7%84%E8%8C%83/" target="_blank" rel="noreferrer">个人文案排版规范 - Power&#39;s Wiki</a></p>',17)])])}const g=r(i,[["render",o]]);export{u as __pageData,g as default};
